import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, EventEmitter, Input, Output, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, Info, CircleCheck, TriangleAlert, CircleX, X } from 'lucide-angular';
const VARIANT_ICON = {
    info: Info,
    success: CircleCheck,
    warning: TriangleAlert,
    danger: CircleX,
};
/**
 * Notification : bandeau d'information système plein-largeur (cf.
 * décision H.2). Différent d'Alert (inline contextuel) et de Toast
 * (éphémère overlay) - persiste jusqu'à fermeture explicite.
 */
let OriNotificationComponent = class OriNotificationComponent {
    constructor() {
        this.variant = 'info';
        this.dismissible = false;
        this.actionLabel = '';
        this.actionHref = '';
        this.actionClick = new EventEmitter();
        this.dismiss = new EventEmitter();
        this.open = true;
        this.XIcon = X;
    }
    iconFor(variant) {
        return VARIANT_ICON[variant];
    }
    get notificationClasses() {
        return `ori-notification ori-notification--${this.variant}`;
    }
    onDismiss() {
        this.open = false;
        this.dismiss.emit();
    }
    static { this.propDecorators = {
        variant: [{ type: Input }],
        dismissible: [{ type: Input }],
        actionLabel: [{ type: Input }],
        actionHref: [{ type: Input }],
        actionClick: [{ type: Output }],
        dismiss: [{ type: Output }]
    }; }
};
OriNotificationComponent = __decorate([
    Component({
        selector: 'ori-notification',
        standalone: true,
        imports: [LucideAngularModule],
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    @if (open) {
      <div [attr.role]="variant === 'danger' ? 'alert' : 'status'" [class]="notificationClasses">
        <lucide-icon
          [img]="iconFor(variant)"
          [size]="20"
          class="ori-notification__icon"
          aria-hidden="true"
        ></lucide-icon>
        <div class="ori-notification__content">
          <span><ng-content></ng-content></span>
          @if (actionLabel && actionHref) {
            <a [href]="actionHref" class="ori-notification__action">{{ actionLabel }}</a>
          } @else if (actionLabel) {
            <button
              type="button"
              class="ori-notification__action"
              (click)="actionClick.emit($event)"
            >
              {{ actionLabel }}
            </button>
          }
        </div>
        @if (dismissible) {
          <button
            type="button"
            class="ori-notification__close"
            aria-label="Fermer"
            (click)="onDismiss()"
          >
            <lucide-icon [img]="XIcon" [size]="16" aria-hidden="true"></lucide-icon>
          </button>
        }
      </div>
    }
  `,
    })
], OriNotificationComponent);
export { OriNotificationComponent };
